CREATE PROC [dbo].[CREATE_EXP] @FromDate datetime, @ToDate datetime AS IF OBJECT_ID('dbo.[EXP]','U') IS NOT NULL DROP TABLE [EXP] IF OBJECT_ID('dbo.[EXP_Info]','U') IS NOT NULL DROP TABLE [EXP_Info] CREATE TABLE [EXP] ( [Export Type] varchar(8) , [Invoice Number] varchar(32) , [Invoice date] varchar(21) , [Invoice Value] decimal , [Port Code] varchar(32) ,[Shiping Bill Number] varchar(32) , [Shiping Bill Date] varchar(21) , [Rate] decimal, [Taxable Value] decimal ) CREATE TABLE EXP_Info ( [No. Of Invoices] decimal, [Total Invoice Value] decimal, [No. of Shipping Bill] decimal, [Total Taxable Value] decimal ) INSERT INTO EXP_Info VALUES(0,0,0,0) IF OBJECT_ID('EXP_Header','U') IS NULL CREATE TABLE EXP_Header ([Summary For EXP(6)] Char(1)) INSERT INTO InfoTable Values('EXP',2,'<<Default>>','EXP',6) 